	// Construct the query safely. 
	// Since we have strictly validated both orderBy and sortDir against allow-lists, 
	// using Sprintf here is safe.
	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", orderBy, sortDir)

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		// It is good practice to handle the error from Scan immediately
		if err := rows.Scan(&p.ID, &p.Name, &p.Price); err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	// Check for errors encountered during iteration
	if err = rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

