	sortDirUpper := strings.ToUpper(sortDir)

	// Validate orderBy against the allow-list
	if !validColumns[orderByLower] {
		return nil, errors.New("invalid sort column")
	}

	// Validate sortDir
	if sortDirUpper != "ASC" && sortDirUpper != "DESC" {
