	// Define the specific columns allowed for sorting.
	allowedColumns := map[string]bool{
		"id":    true,
		"name":  true,
		"price": true,
	}

	// Normalize input to lowercase to ensure case-insensitive matching
	orderByLower := strings.ToLower(orderBy)

	if !allowedColumns[orderByLower] {
		return nil, errors.New("invalid sort column")
	}

	// 3. Construct Query
	// It is now safe to use fmt.Sprintf because we have strictly validated
	// that orderByLower is a valid column name and sortDir is either ASC or DESC.
	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", orderByLower, sortDir)

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		err := rows.Scan(&p.ID, &p.Name, &p.Price)
		if err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err = rows.Err(); err != nil {
		return nil, err
	}

