		safeOrderBy = orderBy
	default:
		return nil, errors.New("invalid order by column")
	}

	// Construct the query
	// It is now safe to use fmt.Sprintf because safeOrderBy and sortDir are strictly controlled values.
	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", safeOrderBy, sortDir)

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name, &p.Price); err != nil {
